// Entité CouponUsage
@Entity()
export class CouponUsage {
  @PrimaryGeneratedColumn()
  id: number;

  @ManyToOne(() => Coupon)
  @JoinColumn({ name: 'couponId' })
  coupon: Coupon;

  @Column()
  couponId: number;

  @ManyToOne(() => User)
  @JoinColumn({ name: 'userId' })
  user: User;

  @Column()
  userId: number;

  @ManyToOne(() => Order)
  @JoinColumn({ name: 'orderId' })
  order: Order;

  @Column({ nullable: true })
  orderId: number;

  @Column({ type: 'decimal', precision: 10, scale: 2 })
  discountAmount: number;

  @CreateDateColumn()
  usedAt: Date;
}

// Service
@Injectable()
export class CouponService {
  async applyCouponToOrder(
    code: string,
    orderId: number,
    userId: number,
    cartTotal: number,
  ): Promise<Order> {
    const queryRunner = this.connection.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      // 1. Valider le coupon (reprend la logique de l'exercice 4)
      const validation = await this.validateCoupon(code, cartTotal, userId);
      if (!validation.valid) {
        throw new BadRequestException(validation.message);
      }

      // 2. Verrouiller le coupon pour éviter les utilisations concurrentes (pessimistic lock)
      const coupon = await queryRunner.manager.findOne(Coupon, {
        where: { code },
        lock: { mode: 'pessimistic_write' },
      });

      // 3. Mettre à jour le compteur d'utilisations
      coupon.usedCount += 1;
      await queryRunner.manager.save(coupon);

      // 4. Enregistrer l'utilisation
      const usage = this.couponUsageRepository.create({
        couponId: coupon.id,
        userId,
        orderId,
        discountAmount: validation.discountAmount,
      });
      await queryRunner.manager.save(usage);

      // 5. Mettre à jour la commande avec la réduction
      const order = await queryRunner.manager.findOne(Order, { where: { id: orderId } });
      order.discountAmount = validation.discountAmount;
      order.finalTotal = cartTotal - validation.discountAmount;
      order.couponCode = code;
      await queryRunner.manager.save(order);

      await queryRunner.commitTransaction();

      return order;
    } catch (error) {
      await queryRunner.rollbackTransaction();
      throw error;
    } finally {
      await queryRunner.release();
    }
  }
}
```
